executor_template.command:
python3 -c "
import json, sys, urllib.request, urllib.error, os
args = json.load(sys.stdin)
prompt = (args.get('prompt') or '').strip()
if not prompt:
    print(json.dumps({'success': False, 'error': 'prompt is required'})); sys.exit(0)
working_dir = args.get('working_dir') or os.path.expanduser('~')
working_dir = os.path.expanduser(working_dir)
if not os.path.isdir(working_dir):
    print(json.dumps({'success': False, 'error': f'working_dir does not exist: {working_dir}'})); sys.exit(0)
base = '${MOJO_BASE_URL}'.rstrip('/')
api_key = os.environ.get('MCP_API_KEY', '')
headers = {'Content-Type': 'application/json'}
if api_key:
    headers['MCP-API-Key'] = api_key

tool_args = {'action': 'run_task', 'prompt': prompt, 'working_dir': working_dir}
if args.get('model'):
    tool_args['model'] = args['model']
if args.get('task_id'):
    tool_args['task_id'] = args['task_id']

payload = {'jsonrpc': '2.0', 'id': 1, 'method': 'tools/call', 'params': {'name': 'external_agent', 'arguments': tool_args}}
try:
    req = urllib.request.Request(base + '/mcp', data=json.dumps(payload).encode(), headers=headers)
    with urllib.request.urlopen(req, timeout=25) as r:
        body = json.loads(r.read())
    result = body.get('result', body)
    print(json.dumps({'success': True, 'result': result}))
except urllib.error.HTTPError as e:
    print(json.dumps({'success': False, 'error': f'HTTP {e.code}: {e.read().decode(errors=\"replace\")[:500]}'}))
except urllib.error.URLError as e:
    print(json.dumps({'success': False, 'error': f'Cannot reach MoJo at {base}: {e.reason}'}))
except Exception as e:
    print(json.dumps({'success': False, 'error': f'{type(e).__name__}: {e}'}))
"
